function plot_ring_qpm_result(out, plot_opts)
%PLOT_RING_QPM_RESULT Plot one result generated by run_ring_qpm_case.
% Usage:
%   plot_ring_qpm_result(out)
%   plot_ring_qpm_result('path/to/result.mat')

if nargin < 2, plot_opts = struct(); end
if ischar(out) || isstring(out)
    S = load(char(out));
    if ~isfield(S,'out'), error('The selected file does not contain variable "out".'); end
    out = S.out;
end
plot_opts = fill_default_plot_opts(plot_opts);
if ~isfield(out,'status') || ~strcmp(out.status,'success')
    error('This result is not successful. out.status = %s', out.status);
end

geom = out.geom; select = out.select; scan = out.scan;
lambda_IR = out.lambda_IR(:); lambda_SH = out.lambda_SH(:);
neff_IR = out.neff_IR(:); neff_SH = out.neff_SH(:);
ng_IR = out.ng_IR(:); ng_SH = out.ng_SH(:);
Result_IR = out.Result_IR; Result_SH = out.Result_SH;
Lambda_QPM_um = out.Lambda_QPM_um(:);
GVM_fs_per_mm = out.GVM_fs_per_mm(:);
Walk = out.Walk;
min_Q_IR_sel = out.min_Q_IR_sel;
min_Q_SH_sel = out.min_Q_SH_sel;
%% Optional post-processing crop and center reset
% Compatible logic:
%   1. choose center
%   2. crop wavelength range
%   3. check center is inside cropped range
%   4. recompute derived quantities

if isempty(plot_opts.center_lambda_IR_nm)
    center_IR_plot_um = scan.lambda0_IR;
else
    center_IR_plot_um = plot_opts.center_lambda_IR_nm / 1e3;
end

% ---- crop wavelength range first ----
if ~isempty(plot_opts.lambda_IR_range_nm)

    lambda_range_um = plot_opts.lambda_IR_range_nm / 1e3;

    idx_crop = lambda_IR >= lambda_range_um(1) & ...
               lambda_IR <= lambda_range_um(2);

    if sum(idx_crop) < 5
        error('Too few wavelength points after cropping. Use a wider lambda_IR_range_nm.');
    end

    lambda_IR = lambda_IR(idx_crop);
    lambda_SH = lambda_SH(idx_crop);

    neff_IR = neff_IR(idx_crop);
    neff_SH = neff_SH(idx_crop);

    ng_IR = ng_IR(idx_crop);
    ng_SH = ng_SH(idx_crop);

    Lambda_QPM_um = Lambda_QPM_um(idx_crop);
    GVM_fs_per_mm = GVM_fs_per_mm(idx_crop);

    if isfield(out,'Data_IR') && isfield(out.Data_IR,'Q_sel')
        min_Q_IR_sel = min_finite_plot(out.Data_IR.Q_sel(idx_crop));
    end

    if isfield(out,'Data_SH') && isfield(out.Data_SH,'Q_sel')
        min_Q_SH_sel = min_finite_plot(out.Data_SH.Q_sel(idx_crop));
    end
end

% ---- center must be inside the current wavelength range ----
if center_IR_plot_um < min(lambda_IR) || center_IR_plot_um > max(lambda_IR)
    error(['center_lambda_IR_nm = %.3f nm is outside current plotting range ', ...
           '[%.3f, %.3f] nm.'], ...
           center_IR_plot_um*1e3, min(lambda_IR)*1e3, max(lambda_IR)*1e3);
end

% ---- recompute all derived quantities if requested ----
if plot_opts.recompute_after_crop

    c0 = 299792458;
    center_SH_plot_um = center_IR_plot_um / 2;

    % Recompute ng from current neff(lambda)
    ng_IR = calc_ng_from_neff_plot(lambda_IR, neff_IR);
    ng_SH = calc_ng_from_neff_plot(lambda_SH, neff_SH);

    % Recompute Dint using the post-processing center
    Result_IR = calc_dint_from_neff_plot(lambda_IR, neff_IR, geom.Radius, ...
        center_IR_plot_um, c0, 'IR band');

    Result_SH = calc_dint_from_neff_plot(lambda_SH, neff_SH, geom.Radius, ...
        center_SH_plot_um, c0, 'SH band');

    % Recompute QPM period
    neff_SH_on_half_IR = interp1(lambda_SH(:), neff_SH(:), lambda_IR(:)/2, ...
        'pchip', 'extrap');

    Lambda_QPM_signed_um = lambda_IR(:) ./ ...
        (2 * (neff_SH_on_half_IR(:) - neff_IR(:)));

    Lambda_QPM_um = abs(Lambda_QPM_signed_um);

    % Recompute GVM
    ng_SH_on_half_IR = interp1(lambda_SH(:), ng_SH(:), lambda_IR(:)/2, ...
        'pchip', 'extrap');

    GVM_s_per_m = (ng_SH_on_half_IR(:) - ng_IR(:)) / c0;
    GVM_fs_per_mm = GVM_s_per_m * 1e12;

    % Recompute SHG mismatch center offset
    Walk = calc_shg_frequency_mismatch_plot(Result_IR, Result_SH, center_IR_plot_um);
end

%% Figure 1: neff and QPM period
x_IR_nm = lambda_IR*1e3;
x_SH_equiv_nm = 2*lambda_SH*1e3;

figure('Name','neff and QPM period','Color','w','Position',[120,80,920,520]);
ax1 = axes; hold(ax1,'on');

yyaxis(ax1,'left');
plot(ax1,x_IR_nm,neff_IR,'o-','LineWidth',1.5,'MarkerSize',4, ...
    'DisplayName',sprintf('IR %s%d n_{eff}',upper(select.IR.pol),select.IR.order-1));
plot(ax1,x_SH_equiv_nm,neff_SH,'s-','LineWidth',1.5,'MarkerSize',4, ...
    'DisplayName',sprintf('SH %s%d n_{eff}',upper(select.SH.pol),select.SH.order-1));
ylabel(ax1,'n_{eff}');
ylim_auto_margin(ax1,[neff_IR(:); neff_SH(:)],0.08);

yyaxis(ax1,'right');
plot(ax1,x_IR_nm,Lambda_QPM_um,'^-','LineWidth',1.5,'MarkerSize',4,'DisplayName','\Lambda_{QPM}');
ylabel(ax1,'\Lambda_{QPM} (\mum)');
ylim_auto_margin(ax1,Lambda_QPM_um(:),0.10);

grid(ax1,'on'); box(ax1,'on');
xlabel(ax1,'Fundamental wavelength (nm)');
xlim(ax1,[min(x_IR_nm), max(x_IR_nm)]);
legend(ax1,'Location','best');
ax1.Position(2) = ax1.Position(2) - 0.02;
ax1.Position(4) = ax1.Position(4) - 0.12;
um = char(181);   % micro symbol: µ

titleStr = { ...
    'n_{eff} and QPM period'; ...
    sprintf('R = %.1f %sm, w = %.3f %sm, t_{LN} = %.3f %sm, t_{ridge} = %.3f %sm', ...
        geom.Radius, um, ...
        geom.w_ln, um, ...
        geom.t_ln, um, ...
        geom.t_ridge, um) ...
    };

sgtitle(titleStr, 'Interpreter', 'tex', 'FontWeight', 'normal');
add_top_sh_axis(ax1);

txt = sprintf(['min Qrad of selected branch:\n', ...
               'IR %s%d: %.2e\nSH %s%d: %.2e'], ...
               upper(select.IR.pol), select.IR.order-1, min_Q_IR_sel, ...
               upper(select.SH.pol), select.SH.order-1, min_Q_SH_sel);
annotation('textbox',[0.63 0.17 0.25 0.14],'String',txt,'FitBoxToText','on', ...
    'BackgroundColor','w','EdgeColor',[0.3 0.3 0.3]);

%% Figure 2: ng
figure('Name','ng scan','Color','w','Position',[150,110,850,470]);
ax2 = axes; hold(ax2,'on');
plot(ax2,x_IR_nm,ng_IR,'o-','LineWidth',1.5,'MarkerSize',4, ...
    'DisplayName',sprintf('IR %s%d n_g',upper(select.IR.pol),select.IR.order-1));
plot(ax2,x_SH_equiv_nm,ng_SH,'s-','LineWidth',1.5,'MarkerSize',4, ...
    'DisplayName',sprintf('SH %s%d n_g',upper(select.SH.pol),select.SH.order-1));
grid(ax2,'on'); box(ax2,'on');
xlabel(ax2,'Fundamental wavelength (nm)'); ylabel(ax2,'n_g');
xlim(ax2,[min(x_IR_nm), max(x_IR_nm)]);
ylim_auto_margin(ax2,[ng_IR(:); ng_SH(:)],0.08);
legend(ax2,'Location','best');
ax2.Position(2)=ax2.Position(2)-0.03;
ax2.Position(4)=ax2.Position(4)-0.08;
sgtitle('Group index from n_{eff}(\lambda)');
add_top_sh_axis(ax2);

%% Figure 3: Dint
figure('Name','Dint','Color','w','Position',[180,100,850,620]);
tiledlayout(2,1,'TileSpacing','compact','Padding','compact');

x_IR = Result_IR.mu(:);
y_IR = Result_IR.Dint_Hz(:)/1e9;
switch lower(plot_opts.SH_mu_axis)
    case 'equiv'
        x_SH = Result_SH.mu(:)/2;
        x_SH_label = '\mu_{IR} equivalent  (\mu_{SH}/2)';
        title_SH_extra = 'x-axis plotted as \mu_{SH}/2';
    case 'raw'
        x_SH = Result_SH.mu(:);
        x_SH_label = '\mu_{SH}';
        title_SH_extra = 'x-axis plotted as \mu_{SH}';
    otherwise
        error('plot_opts.SH_mu_axis must be "equiv" or "raw".');
end
y_SH = Result_SH.Dint_Hz(:)/1e9;
x_common = common_xlim(x_IR,x_SH);

nexttile;
plot(x_IR,y_IR,'o-','LineWidth',1.5,'MarkerSize',4);
grid on; box on; ylabel('D_{int}/2\pi (GHz)');
title(sprintf('IR band, %s%d',upper(select.IR.pol),select.IR.order-1));
xlim(x_common); ylim_auto_margin(gca,y_IR(x_IR>=x_common(1) & x_IR<=x_common(2)),0.10);

nexttile;
plot(x_SH,y_SH,'s-','LineWidth',1.5,'MarkerSize',4);
grid on; box on; xlabel(x_SH_label); ylabel('D_{int}/2\pi (GHz)');
title(sprintf('SH band, %s%d, %s',upper(select.SH.pol),select.SH.order-1,title_SH_extra));
xlim(x_common); ylim_auto_margin(gca,y_SH(x_SH>=x_common(1) & x_SH<=x_common(2)),0.10);
sgtitle(sprintf('Integrated dispersion, R = %.1f %sm', geom.Radius, um), ...
    'Interpreter', 'tex', ...
    'FontWeight', 'normal');

%% Figure 4: GVM and SHG mismatch
figure('Name','GVM and SHG mismatch','Color','w','Position',[210,100,850,620]);
tiledlayout(2,1,'TileSpacing','compact','Padding','compact');

nexttile;
plot(lambda_IR*1e3,GVM_fs_per_mm,'o-','LineWidth',1.5,'MarkerSize',4);
grid on; box on; xlabel('Fundamental wavelength (nm)'); ylabel('GVM (fs/mm)');
title('GVM = (n_{g,SH} - n_{g,IR})/c');
xlim([min(lambda_IR)*1e3, max(lambda_IR)*1e3]);
ylim_auto_margin(gca,GVM_fs_per_mm(:),0.10);
xline(center_IR_plot_um*1e3,'--');

nexttile;
plot(Walk.mu_IR_use,Walk.Delta_f_rel_Hz/1e9,'s-','LineWidth',1.5,'MarkerSize',4);
grid on; box on; xlabel('\mu_{IR}'); ylabel('\Delta f_{SHG} (GHz)');
title('\Delta f_{SHG} = [f_{SH}(\mu_{SH}=2\mu_{IR}) - 2f_{IR}(\mu_{IR})] - center offset');
xlim_auto_integer(gca,Walk.mu_IR_use);
ylim_auto_margin(gca,Walk.Delta_f_rel_Hz(:)/1e9,0.10);
xline(0,'--');
end

function plot_opts = fill_default_plot_opts(plot_opts)

if ~isfield(plot_opts,'SH_mu_axis')
    plot_opts.SH_mu_axis = 'equiv';
end

% Fundamental wavelength plotting/post-processing range in nm.
% [] means use full saved range.
if ~isfield(plot_opts,'lambda_IR_range_nm')
    plot_opts.lambda_IR_range_nm = [];
end

% Fundamental center wavelength in nm.
% [] means use out.scan.lambda0_IR.
if ~isfield(plot_opts,'center_lambda_IR_nm')
    plot_opts.center_lambda_IR_nm = [];
end

% Recompute derived quantities after crop / center change.
if ~isfield(plot_opts,'recompute_after_crop')
    plot_opts.recompute_after_crop = true;
end

end

function axTop = add_top_sh_axis(axMain)
pos = axMain.Position;
axTop = axes('Position',pos,'XAxisLocation','top','YAxisLocation','right', ...
    'Color','none','XLim',axMain.XLim,'YLim',axMain.YLim, ...
    'XTick',axMain.XTick,'YTick',[],'Box','off');
xt = axMain.XTick; xt_sh = xt/2;
set(axTop,'XTickLabel',arrayfun(@(x) sprintf('%.0f',x),xt_sh,'UniformOutput',false));
xlabel(axTop,'SH wavelength (nm)');
axTop.YColor='none'; axTop.XColor=axMain.XColor; axTop.FontSize=axMain.FontSize;
axes(axMain);
end

function ylim_auto_margin(ax,y,margin_frac)
y = y(:); y = y(isfinite(y)); if isempty(y), return; end
ymin = min(y); ymax = max(y);
if ymax == ymin, dy = max(abs(ymax),1)*0.05; else, dy = (ymax-ymin)*margin_frac; end
ylim(ax,[ymin-dy, ymax+dy]);
end

function xl = common_xlim(x1,x2)
x1=x1(:); x2=x2(:); xmin=max([min(x1),min(x2)]); xmax=min([max(x1),max(x2)]);
if xmin>=xmax, xmin=min([x1;x2]); xmax=max([x1;x2]); end
xl=[floor(xmin), ceil(xmax)];
end

function xlim_auto_integer(ax,x)
x=x(:); x=x(isfinite(x)); if isempty(x), return; end
xlim(ax,[floor(min(x)), ceil(max(x))]);
end

function ng = calc_ng_from_neff_plot(lambda_um, neff)

lambda_um = lambda_um(:);
neff = neff(:);

valid = isfinite(lambda_um) & isfinite(neff);
lambda_v = lambda_um(valid);
neff_v = neff(valid);

if numel(lambda_v) < 5
    error('Too few valid neff points for ng calculation after post-processing.');
end

[lambda_v, idx] = sort(lambda_v);
neff_v = neff_v(idx);

neff_smooth = interp1(lambda_v, neff_v, lambda_um, 'pchip', 'extrap');
dneff_dlambda = gradient(neff_smooth, lambda_um);

ng = neff_smooth - lambda_um .* dneff_dlambda;

end

function Result = calc_dint_from_neff_plot(lambda_um, neff, R_um, center_lambda_um, c0, label)

lambda_um = lambda_um(:);
neff = neff(:);

valid = isfinite(lambda_um) & isfinite(neff);
lambda_um = lambda_um(valid);
neff = neff(valid);

if numel(lambda_um) < 5
    error('%s: too few valid neff points to calculate Dint.', label);
end

omega = 2*pi*c0 ./ (lambda_um*1e-6);
m_float = 2*pi*R_um .* neff ./ lambda_um;

[m_sort, idx] = sort(m_float, 'ascend');

omega_sort = omega(idx);
lambda_sort = lambda_um(idx);
neff_sort = neff(idx);

[m_unique, ia] = unique(m_sort, 'stable');

omega_unique = omega_sort(ia);
lambda_unique = lambda_sort(ia);
neff_unique = neff_sort(ia);

neff_center = interp1(lambda_um, neff, center_lambda_um, 'pchip', 'extrap');
m0_float = 2*pi*R_um*neff_center/center_lambda_um;
m0 = round(m0_float);

m_min = ceil(min(m_unique));
m_max = floor(max(m_unique));
m_int = (m_min:m_max).';

if numel(m_int) < 5
    error('%s: too few integer modes. Use a wider wavelength range.', label);
end

omega_m = interp1(m_unique, omega_unique, m_int, 'pchip');
lambda_m_um = interp1(m_unique, lambda_unique, m_int, 'pchip');
neff_m = interp1(m_unique, neff_unique, m_int, 'pchip');

mu = m_int - m0;
idx0 = find(mu == 0, 1);

if isempty(idx0)
    error('%s: center mode m0 is outside the current wavelength range.', label);
end

omega0 = omega_m(idx0);

idx_p1 = find(mu == 1, 1);
idx_m1 = find(mu == -1, 1);

if ~isempty(idx_p1) && ~isempty(idx_m1)
    D1 = (omega_m(idx_p1) - omega_m(idx_m1))/2;
    D2 = omega_m(idx_p1) - 2*omega0 + omega_m(idx_m1);
else
    fit_idx = abs(mu) <= min(3, max(abs(mu)));
    p = polyfit(mu(fit_idx), omega_m(fit_idx), 2);
    D1 = p(2);
    D2 = 2*p(1);
end

Dint = omega_m - (omega0 + D1*mu);

Result.label = label;
Result.R_um = R_um;
Result.center_lambda_input_um = center_lambda_um;

Result.m0_float = m0_float;
Result.m0 = m0;

Result.m_int = m_int(:);
Result.mu = mu(:);

Result.lambda_m_um = lambda_m_um(:);
Result.neff_m = neff_m(:);

Result.omega_rad_s = omega_m(:);
Result.omega0_rad_s = omega0;

Result.D1_rad_s = D1;
Result.D2_rad_s = D2;
Result.Dint_rad_s = Dint(:);

Result.freq_Hz = omega_m(:)/(2*pi);
Result.freq0_Hz = omega0/(2*pi);
Result.D1_Hz = D1/(2*pi);
Result.D2_Hz = D2/(2*pi);
Result.Dint_Hz = Dint(:)/(2*pi);

end

function Walk = calc_shg_frequency_mismatch_plot(Result_IR, Result_SH, center_lambda_IR)

mu_IR_all = Result_IR.mu(:);
f_IR_all = Result_IR.freq_Hz(:);

mu_SH_all = Result_SH.mu(:);
f_SH_all = Result_SH.freq_Hz(:);

lambda_IR_all = Result_IR.lambda_m_um(:);
lambda_SH_all = Result_SH.lambda_m_um(:);

mu_SH_req = 2*mu_IR_all;

[tf, loc] = ismember(mu_SH_req, mu_SH_all);

mu_IR_use = mu_IR_all(tf);
mu_SH_use = mu_SH_req(tf);

f_IR_use = f_IR_all(tf);
f_SH_use = f_SH_all(loc(tf));

lambda_IR_use = lambda_IR_all(tf);
lambda_SH_use = lambda_SH_all(loc(tf));

Delta_f_SHG_Hz = f_SH_use - 2*f_IR_use;

idx0 = find(mu_IR_use == 0, 1);

if isempty(idx0)
    [~, idx0] = min(abs(lambda_IR_use - center_lambda_IR));
end

Delta_f0_Hz = Delta_f_SHG_Hz(idx0);
Delta_f_rel_Hz = Delta_f_SHG_Hz - Delta_f0_Hz;

Walk.mu_IR_use = mu_IR_use;
Walk.mu_SH_use = mu_SH_use;

Walk.f_IR_use_Hz = f_IR_use;
Walk.f_SH_use_Hz = f_SH_use;

Walk.lambda_IR_use_um = lambda_IR_use;
Walk.lambda_SH_use_um = lambda_SH_use;

Walk.Delta_f_SHG_Hz = Delta_f_SHG_Hz;
Walk.Delta_f0_Hz = Delta_f0_Hz;
Walk.Delta_f_rel_Hz = Delta_f_rel_Hz;

end

function val = min_finite_plot(x)

x = x(:);
x = x(isfinite(x));

if isempty(x)
    val = NaN;
else
    val = min(x);
end

end